import { z } from 'zod';

function validateStringMinMax(input: unknown, min: number, max: number): { success: boolean; error?: string } {
  const schema = z.string().min(min).max(max);
  const result = schema.safeParse(input);
  if (result.success) return { success: true };
  return { success: false, error: result.error.message };
}

export { validateStringMinMax };
export default validateStringMinMax;
